package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  @Test
  void enableComplexMapKeySerialization_shouldSetComplexMapKeySerializationTrue_andReturnThis() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    GsonBuilder returned = builder.enableComplexMapKeySerialization();

    assertSame(builder, returned);

    // Use reflection to check private field complexMapKeySerialization
    var field = GsonBuilder.class.getDeclaredField("complexMapKeySerialization");
    field.setAccessible(true);
    boolean fieldValue = field.getBoolean(builder);
    assertTrue(fieldValue);
  }
}
